 37 |     private var lastDownTime = 0L
 38 |     private var downCount = 0
 39 |     
 40 |     private val CLICK_GAP = 400L
 41 | 
 42 |     private var isVolUpPressed = false
 43 |     private var isVolDownPressed = false
 44 |     private var isWaitingForTapHold = false
 45 |     private var isWaitingForDownTapHold = false
 46 |     private var lastCameraPackage = ""
 47 |     private var isLensSwitchPending = false
 48 |     private var isEarphoneNavMode = false
 49 |     private var isLongPressTriggered = false
