 51 |     private val volUpLongPressRunnable = Runnable {
 52 |         isEarphoneNavMode = !isEarphoneNavMode
 53 |         isLongPressTriggered = true
 54 |         val status = if (isEarphoneNavMode) "Earphone Navigation Activated" else "Earphone Navigation Deactivated"
 55 |         DebugLogger.log("MODE", status)
 56 |         speak(status, true)
 57 |         hapticPulse(500)
 58 |         
 59 |         if (isEarphoneNavMode) {
 60 |             val intent = Intent(this@KeyInterceptService, PlaybackService::class.java).apply {
 61 |                 action = "START_NAV"
 62 |             }
