 67 |     override fun onKeyEvent(event: KeyEvent): Boolean {
 68 |         val prefs = getSharedPreferences("monitor_prefs", Context.MODE_PRIVATE)
 69 |         // Absolute first check - if inactive, pass through immediately
 70 |         if (!prefs.getBoolean("is_active", true)) return false
 71 | 
 72 |         val pm = getSystemService(Context.POWER_SERVICE) as PowerManager
 73 |         val isScreenOn = pm.isInteractive
 74 |         if (!prefs.getBoolean("keys_enabled", true)) return false
 75 | 
 76 |         val keyCode = event.keyCode
 77 |         val action = event.action
 78 |         val isLongPress = (event.eventTime - event.downTime) > 600
 79 | 
 80 |         // 1. Camera Context & Emergency Logic
 81 |         val root = rootInActiveWindow
 82 |         val pkg = root?.packageName?.toString() ?: ""
 83 |         val isCamOpen = pkg.contains("camera") || pkg.contains("lens")
 84 | 
 85 |         if (isCamOpen && (keyCode == KeyEvent.KEYCODE_VOLUME_UP || keyCode == KeyEvent.KEYCODE_VOLUME_DOWN)) {
 86 |             if (keyCode == KeyEvent.KEYCODE_VOLUME_UP && action == KeyEvent.ACTION_UP) {
 87 |                 val now = System.currentTimeMillis()
 88 |                 if (now - lastUpTime < 400 && blockerOverlay != null) {
 89 |                     DebugLogger.log("BLOCKER", "Emergency Removal via VolUp Double-Tap")
 90 |                     removeTouchBlocker()
 91 |                     return true // Consume to prevent shutter on emergency exit
 92 |                 }
 93 |                 lastUpTime = now
 94 |             }
 95 |             // Pass through to the system so the Camera App can handle the shutter
 96 |             return false 
 97 |         }
 98 | 
 99 |         // 2. Headset Hijack Logic (Highest Priority)
100 |         val isHeadsetKey = keyCode == KeyEvent.KEYCODE_HEADSETHOOK || 
101 |                           keyCode == KeyEvent.KEYCODE_MEDIA_PLAY_PAUSE || 
102 |                           keyCode == KeyEvent.KEYCODE_MEDIA_NEXT || 
103 |                           keyCode == KeyEvent.KEYCODE_MEDIA_PREVIOUS
104 | 
105 |         if (isHeadsetKey) {
106 |             if (action == KeyEvent.ACTION_DOWN) {
107 |                 if (event.repeatCount == 0) {
108 |                     lastHeadsetDownTime = event.eventTime
109 |                     val pm = getSystemService(Context.POWER_SERVICE) as PowerManager
110 |                     val wl = pm.newWakeLock(PowerManager.PARTIAL_WAKE_LOCK, "UniversalApp::KeyHijack")
111 |                     wl.acquire(500)
112 |                 }
113 |                 return true 
114 |             }
115 |             if (action == KeyEvent.ACTION_UP) {
116 |                 val duration = event.eventTime - lastHeadsetDownTime
117 |                 handler.removeCallbacks(headsetGestureRunnable)
118 |                 
119 |                 // Append 'L' for Long, 'S' for Short to the sequence string
120 |                 gestureSequence += if (duration > 600) "L" else "S"
121 |                 
122 |                 handler.postDelayed(headsetGestureRunnable, 450)
123 |                 return true
124 |             }
125 |         }
126 | 
127 |         // 3. Volume Key DOWN Logic
128 |         if (action == KeyEvent.ACTION_DOWN) {
129 |             val now = System.currentTimeMillis()
130 |             if (keyCode == KeyEvent.KEYCODE_VOLUME_UP) {
131 |                 isVolUpPressed = true
132 |                 isWaitingForTapHold = (now - lastUpTime < 800)
133 |             }
134 |             if (keyCode == KeyEvent.KEYCODE_VOLUME_DOWN) {
135 |                 isVolDownPressed = true
136 |                 isWaitingForDownTapHold = (now - lastDownTime < 800)
137 |             }
138 | 
139 |             if (event.repeatCount > 0) return true
140 |             if (isVolUpPressed && isVolDownPressed) return true
141 | 
142 |             when (keyCode) {
143 |                 KeyEvent.KEYCODE_VOLUME_UP -> {
144 |                     if (event.repeatCount == 0) {
145 |                         isLongPressTriggered = false
146 |                         handler.postDelayed(volUpLongPressRunnable, 5000)
147 |                     }
148 |                     val now = System.currentTimeMillis()
149 |                     if (now - lastUpTime < CLICK_GAP) upCount++ else upCount = 1
150 |                     lastUpTime = now
151 |                     return true
152 |                 }
153 |                 KeyEvent.KEYCODE_VOLUME_DOWN -> {
154 |                     val now = System.currentTimeMillis()
155 |                     if (now - lastDownTime < CLICK_GAP) downCount++ else downCount = 1
156 |                     lastDownTime = now
157 |                     return true
158 |                 }
159 |             }
160 |         }
161 | 
162 |         // 4. Volume Key UP Logic
163 |         if (action == KeyEvent.ACTION_UP) {
164 |             val wasBothPressed = isVolUpPressed && isVolDownPressed
165 |             if (keyCode == KeyEvent.KEYCODE_VOLUME_UP) isVolUpPressed = false
166 |             if (keyCode == KeyEvent.KEYCODE_VOLUME_DOWN) isVolDownPressed = false
167 | 
168 |             if (wasBothPressed) {
169 |                 val intent = Intent(this, PlaybackService::class.java)
170 |                 intent.action = if (isLongPress) "RESET" else "PAUSE"
171 |                 startService(intent)
172 |                 return true
173 |             }
174 | 
175 | 
176 | 
177 |             when (keyCode) {
178 |                 KeyEvent.KEYCODE_VOLUME_UP -> {
179 |                     handler.removeCallbacks(volUpLongPressRunnable)
180 |                     if (isLongPressTriggered) {
181 |                         isLongPressTriggered = false
182 |                         upCount = 0
183 |                         isWaitingForTapHold = false
184 |                         return true
185 |                     }
186 |                     
187 |                     val duration = event.eventTime - event.downTime
188 |                     if (isWaitingForTapHold && duration > 500) {
189 |                         toggleCamera()
190 |                         isWaitingForTapHold = false
191 |                         upCount = 0 
192 |                         return true 
193 |                     }
194 |                     isWaitingForTapHold = false
195 |                     handlePress("UP", upCount, isLongPress)
196 |                 }
197 |                 KeyEvent.KEYCODE_VOLUME_DOWN -> {
198 |                     val duration = event.eventTime - event.downTime
199 |                     if (isWaitingForDownTapHold && duration > 500) {
200 |                         triggerReset()
201 |                         isWaitingForDownTapHold = false
202 |                         downCount = 0
203 |                         return true
204 |                     }
205 |                     isWaitingForDownTapHold = false
206 |                     handlePress("DOWN", downCount, isLongPress)
207 |                 }
208 |             }
209 |             return true
210 |         }
211 | 
212 |         return super.onKeyEvent(event)
213 |     }
