297 |                 count == 1 -> intent.apply { action = "PREVIOUS" }
298 |                 count == 2 -> intent.apply { action = "PLAY_TYPE"; putExtra("type", "mc") }
299 |                 count == 3 -> intent.apply { action = "PLAY_TYPE"; putExtra("type", "ma") }
300 |                 else -> { /* No action */ }
301 |             }
302 |         }
303 |         
304 |         if (intent.action != null) {
305 |             startService(intent)
306 |         }
307 |     }
