309 |     private fun prepareWideLens(): Boolean {
310 |         val root = rootInActiveWindow ?: return false
311 |         
312 |         var lensNode: AccessibilityNodeInfo? = null
313 |         val searchTerms = listOf(".5", "0.5", "0,5", "0.6", "0.5x", "0,5x", "ultra", "wide", "zoom out")
314 |         val bounds = Rect()
315 | 
316 |         val queue = LinkedList<AccessibilityNodeInfo>()
317 |         queue.add(root)
318 |         while (!queue.isEmpty()) {
319 |             val node = queue.poll() ?: continue
320 |             val text = node.text?.toString()?.lowercase() ?: ""
321 |             val desc = node.contentDescription?.toString()?.lowercase() ?: ""
322 |             
323 |             val match = searchTerms.find { (text.contains(it) || desc.contains(it)) && !text.contains("1x") }
324 | 
325 |             if (match != null) {
326 |                 var current: AccessibilityNodeInfo? = node
327 |                 var depth = 0
328 |                 while (current != null && depth < 6) {
329 |                     if (current.isClickable) {
330 |                         lensNode = current
331 |                         break
332 |                     }
333 |                     current = current.parent
334 |                     depth++
335 |                 }
336 |                 if (lensNode != null) break
337 |             }
338 |             for (i in 0 until node.childCount) { node.getChild(i)?.let { queue.add(it) } }
339 |         }
340 | 
341 |         return if (lensNode != null) {
342 |             // Try Virtual Click first (Robust Verification)
343 |             val success = lensNode.performAction(AccessibilityNodeInfo.ACTION_CLICK)
344 |             
345 |             if (success) {
346 |                 DebugLogger.log("LENS_FLOW", "Virtual click SUCCESS")
347 |                 speak("Wide lens activated", true)
348 |                 hapticPulse(50)
349 |                 true
350 |             } else {
351 |                 // Fallback to Physical Tap for Samsung/Google Camera
352 |                 lensNode.getBoundsInScreen(bounds)
353 |                 val x = bounds.centerX().toFloat()
354 |                 val y = bounds.centerY().toFloat()
355 |                 
356 |                 val clickPath = Path().apply { moveTo(x, y) }
357 |                 val gesture = GestureDescription.Builder()
358 |                     .addStroke(GestureDescription.StrokeDescription(clickPath, 0, 50))
359 |                     .build()
360 |                 
361 |                 dispatchGesture(gesture, null, null)
362 |                 DebugLogger.log("LENS_FLOW", "Virtual click REJECTED. Physical tap dispatched to $x, $y")
363 |                 // Return false so the retry loop continues to verify the switch
364 |                 false
365 |             }
366 |         } else {
367 |             false
368 |         }
369 |     }
