371 |     private fun attemptLensSwitch(retries: Int) {
372 |         if (!isLensSwitchPending) return
373 |         
374 |         if (retries <= 0) {
375 |             DebugLogger.log("LENS_FLOW", "Search timed out. Applying fallback coordinates.")
376 |             clickLensCoordinatesFallback()
377 |             isLensSwitchPending = false
378 |             val prefs = getSharedPreferences("monitor_prefs", Context.MODE_PRIVATE)
379 |             if (prefs.getBoolean("touch_blocker", false)) showTouchBlocker()
380 |             return
381 |         }
382 | 
383 |         handler.postDelayed({
384 |             if (!isLensSwitchPending) return@postDelayed
385 |             
386 |             val success = prepareWideLens()
387 |             if (success) {
388 |                 DebugLogger.log("LENS_FLOW", "Lens switch CONFIRMED.")
389 |                 isLensSwitchPending = false
390 |                 val prefs = getSharedPreferences("monitor_prefs", Context.MODE_PRIVATE)
391 |                 if (prefs.getBoolean("touch_blocker", false)) showTouchBlocker()
392 |             } else {
393 |                 attemptLensSwitch(retries - 1)
394 |             }
395 |         }, 500)
396 |     }
