398 |     private fun clickLensCoordinatesFallback() {
399 |         val metrics = resources.displayMetrics
400 |         // Standard ultra-wide button is usually centered but slightly above the shutter
401 |         val x = metrics.widthPixels / 2f
402 |         val y = metrics.heightPixels * 0.70f 
403 | 
404 |         val clickPath = Path().apply { moveTo(x, y) }
405 |         val gesture = GestureDescription.Builder()
406 |             .addStroke(GestureDescription.StrokeDescription(clickPath, 0, 50))
407 |             .build()
408 |         dispatchGesture(gesture, null, null)
409 |         hapticPulse(100)
