412 |     private fun performPinchFallback() {
413 |         val metrics = resources.displayMetrics
414 |         val centerX = metrics.widthPixels / 2f
415 |         val centerY = metrics.heightPixels / 2f
416 |         val path1 = android.graphics.Path().apply { moveTo(100f, 100f); lineTo(centerX - 50, centerY - 50) }
417 |         val path2 = android.graphics.Path().apply { moveTo(metrics.widthPixels - 100f, 100f); lineTo(centerX + 50, centerY - 50) }
418 |         val stroke1 = GestureDescription.StrokeDescription(path1, 0, 500)
419 |         val stroke2 = GestureDescription.StrokeDescription(path2, 0, 500)
420 |         val gesture = GestureDescription.Builder().addStroke(stroke1).addStroke(stroke2).build()
421 |         
422 |         dispatchGesture(gesture, object : AccessibilityService.GestureResultCallback() {
423 |             override fun onCompleted(gestureDescription: GestureDescription) = DebugLogger.log("GESTURE", "Pinch SUCCESS")
424 |             override fun onCancelled(gestureDescription: GestureDescription) = DebugLogger.log("GESTURE", "Pinch FAILED")
425 |         }, null)
426 |     }
