428 |     private fun smartShutterClick() {
429 |         val root = rootInActiveWindow
430 |         val pkg = root?.packageName?.toString() ?: ""
431 |         val isCamera = pkg.contains("camera") || pkg.contains("lens")
432 | 
433 |         if (!isCamera) {
434 |             DebugLogger.log("SHUTTER", "Blocked: Camera not in foreground ($pkg)")
435 |             speak("Camera is not launched yet", true)
436 |             return
437 |         }
438 | 
439 |         var foundNode: AccessibilityNodeInfo? = null
440 |         if (root != null) {
441 |             val targets = listOf("shutter", "take picture", "capture", "camera_shutter", "bottom_bar_shutter")
442 |             val queue = LinkedList<AccessibilityNodeInfo>()
443 |             queue.add(root)
444 |             
445 |             while (!queue.isEmpty()) {
446 |                 val node = queue.poll() ?: continue
447 |                 val id = node.viewIdResourceName?.lowercase() ?: ""
448 |                 val desc = node.contentDescription?.toString()?.lowercase() ?: ""
449 |                 
450 |                 if (targets.any { id.contains(it) || desc.contains(it) } && node.isClickable) {
451 |                     foundNode = node
452 |                     break
453 |                 }
454 |                 for (i in 0 until node.childCount) { node.getChild(i)?.let { queue.add(it) } }
455 |             }
456 |         }
457 | 
458 |         if (foundNode != null) {
459 |             DebugLogger.log("AUTO", "Smart Shutter Active")
460 |             speak("Capturing image")
461 |             hapticPulse(100)
462 |             foundNode.performAction(android.view.accessibility.AccessibilityNodeInfo.ACTION_CLICK)
463 |         } else {
464 |             DebugLogger.log("AUTO", "Shutter Node Missing")
465 |             speak("Shutter button not visible, using coordinate fallback")
466 |             logUiHierarchy()
467 |             clickShutterCoordinates()
468 |         }
469 |     }
