530 |     private fun processHeadsetGesture(sequence: String) {
531 |         if (sequence.isEmpty()) return
532 |         val intent = Intent(this, PlaybackService::class.java)
533 |         val pm = getSystemService(Context.POWER_SERVICE) as PowerManager
534 |         
535 |         val root = rootInActiveWindow
536 |         val pkg = root?.packageName?.toString() ?: ""
537 |         val isCam = pkg.contains("camera") || pkg.contains("lens")
538 | 
539 |         // Global Priority: If screen is off, wake up
540 |         if (!pm.isInteractive && sequence == "S") {
541 |             wakeDevice(pm)
542 |             return
543 |         }
544 | 
545 |         // Camera Priority: If camera is open, 'S' is ALWAYS shutter
546 |         if (isCam && sequence == "S") {
547 |             DebugLogger.log("HEADSET", "Camera detected: Overriding 'S' to Shutter")
548 |             smartShutterClick()
549 |             return
550 |         }
551 | 
552 |         if (isEarphoneNavMode) {
553 |             // Simplified Navigation Mode Logic
554 |             when (sequence) {
555 |                 "S" -> intent.action = "PAUSE"
556 |                 "SS" -> intent.action = "NEXT"
557 |                 "L" -> intent.action = "NEXT_CATEGORY"
558 |                 "LS" -> {
559 |                     toggleCamera()
560 |                     return // Exit so we don't try to start PlaybackService
561 |                 }
562 |                 else -> {
563 |                    if (sequence.contains("L")) intent.action = "NEXT_CATEGORY"
564 |                    else intent.action = "NEXT"
565 |                 }
566 |             }
567 |             if (intent.action != null) startService(intent)
568 |         } else {
569 |             // Standby/System Mode Logic
570 |             when (sequence) {
571 |                 "S" -> smartShutterClick()
572 |                 "SS" -> toggleCamera()
573 |                 "L" -> speak("System ready. Long press detected.", true)
574 |                 else -> speak("$sequence detected", true)
575 |             }
576 |         }
577 |         
578 |         DebugLogger.log("HEADSET_NAV", "Mode: $isEarphoneNavMode, Seq: $sequence")
579 |     }
