588 |     private fun recursiveLog(node: AccessibilityNodeInfo, depth: Int) {
589 |         if (depth > 15) return
590 |         val sb = StringBuilder()
591 |         repeat(depth) { sb.append(".") }
592 |         
593 |         val text = node.text?.toString() ?: ""
594 |         val desc = node.contentDescription?.toString() ?: ""
595 |         val id = node.viewIdResourceName ?: ""
596 |         val bounds = Rect()
597 |         node.getBoundsInScreen(bounds)
598 | 
599 |         sb.append("[").append(node.className?.toString()?.split(".")?.last() ?: "Unknown").append("] ")
600 |         if (text.isNotEmpty()) sb.append("T:$text ")
601 |         if (desc.isNotEmpty()) sb.append("D:$desc ")
602 |         if (id.isNotEmpty()) sb.append("ID:$id ")
603 |         sb.append("B:(${bounds.left},${bounds.top})")
604 |         
605 |         if (node.isClickable || text.contains("0") || desc.contains("0")) {
606 |              DebugLogger.log("UI_TRACE", sb.toString())
607 |         }
608 |         
609 |         for (i in 0 until node.childCount) {
610 |             node.getChild(i)?.let { recursiveLog(it, depth + 1) }
611 |         }
612 |     }
