614 |     override fun onAccessibilityEvent(event: AccessibilityEvent?) {
615 |         val type = event?.eventType
616 |         val pkg = event?.packageName?.toString() ?: ""
617 |         
618 |         // Omniscient Logging: Track every app transition to find hidden camera packages
619 |         if (type == AccessibilityEvent.TYPE_WINDOW_STATE_CHANGED) {
620 |             DebugLogger.log("WINDOW_TRACE", "Focus moved to: $pkg")
621 |         }
622 | 
