 85 |     override fun onSensorChanged(event: SensorEvent?) {
 86 |         val ctx = applicationContext
 87 |         
 88 |         // 1. SHAKE DETECTION (Requires holding Volume Up)
 89 |         if (event?.sensor?.type == Sensor.TYPE_ACCELEROMETER) {
 90 |             if (!LockManager.isVolumeUpHeld) {
 91 |                 shakeTimestamps.clear()
 92 |                 return
 93 |             }
 94 | 
 95 |             val x = event.values[0]
 96 |             val y = event.values[1]
 97 |             val z = event.values[2]
 98 |             val magnitude = Math.sqrt((x * x + y * y + z * z).toDouble()).toFloat()
 99 | 
100 |             if (magnitude > shakeThreshold) {
101 |                 val now = System.currentTimeMillis()
102 |                 
103 |                 // Debounce: Only count one shake every 150ms to ensure directional change
104 |                 if (now - lastShakeTimestamp > 150) {
105 |                     shakeTimestamps.addLast(now)
106 |                     lastShakeTimestamp = now
107 |                     
108 |                     while (shakeTimestamps.isNotEmpty() && now - shakeTimestamps.first > shakeWindow) {
109 |                         shakeTimestamps.removeFirst()
110 |                     }
111 | 
112 |                     DebugLogger.log("EXORCIST", "Distinct Shake Detected (${shakeTimestamps.size}/3)")
113 |                     if (shakeTimestamps.size >= 3) {
114 |                         shakeTimestamps.clear()
115 |                         if (!LockManager.isWhisperMode(ctx)) {
116 |                             DebugLogger.log("EXORCIST", "TRIGGER: Conditions met. Launching Protocol.")
117 |                             LockManager.startWhisperMode(ctx, isReflex = true)
118 |                             val vibrator = getSystemService(Context.VIBRATOR_SERVICE) as android.os.Vibrator
119 |                             vibrator.vibrate(longArrayOf(0, 500, 200, 500), -1)
120 |                             
121 |                                                     val intent = Intent(ctx, LockdownActivity::class.java).apply {
122 |                             putExtra("BLOCK_TYPE", "WHISPER_PROTOCOL")
123 |                             addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_SINGLE_TOP)
124 |                         }
125 |                         startLocationTracking()
126 |                         startActivity(intent)
127 |                         }
128 |                     }
129 |                 }
130 |             }
131 |         }
132 | 
133 |         // 2. STEP DETECTION (ENFORCEMENT)
134 |         if (event?.sensor?.type == Sensor.TYPE_STEP_DETECTOR) {
135 |             if (LockManager.isWhisperMode(ctx)) {
136 |                 val currentDist = LockManager.currentDisplacement
137 |                 
138 |                 // INTERLOCK 1: Step requires GPS progress
139 |                 // We allow the first 2 steps to count without GPS to break the 'zero-zero' deadlock
140 |                 val totalSteps = LockManager.getWhisperSteps(ctx)
141 |                 if (currentDist > (lastVerifiedDistForStep + 0.4f) || totalSteps < 2) {
142 |                     LockManager.addWhisperStep(ctx)
143 |                     lastVerifiedDistForStep = currentDist
144 |                     
145 |                     val steps = LockManager.getWhisperSteps(ctx)
146 |                     if (steps >= 30 && currentDist >= 20f) {
147 |                         DebugLogger.log("EXORCIST", "Release Authorized. Steps: $steps, Dist: ${currentDist}m")
148 |                         LockManager.stopWhisperMode(ctx)
149 |                         stopLocationTracking()
150 |                     }
151 |                 } else {
152 |                     DebugLogger.log("EXORCIST_SYNC", "Step ignored: No GPS displacement detected.")
153 |                 }
154 |             }
155 |         }
156 |     }
