158 |     override fun onLocationChanged(location: android.location.Location) {
159 |         if (LockManager.isWhisperMode(applicationContext)) {
160 |             // 1. ANTI-SPOOFING
161 |             val isMock = if (android.os.Build.VERSION.SDK_INT >= 31) location.isMock else @Suppress("DEPRECATION") location.isFromMockProvider
162 |             if (isMock) return
163 | 
164 |             // 2. ACCURACY FILTER: Ignore garbage data (Drift)
165 |             // Anything worse than 25m is usually a bounce off a wall.
166 |             if (location.accuracy > 25f) {
167 |                 DebugLogger.log("GPS_DRIFT", "Ignored low accuracy: ${location.accuracy}m")
168 |                 return
169 |             }
170 | 
171 |             val start = LockManager.startLocation
172 |             
173 |             // 3. ANCHOR STABILIZATION
174 |             if (start == null) {
175 |                 // Ignore first 3 updates to allow GPS to settle/discard cached data
176 |                 if (locationSettlementCount < 3) {
177 |                     locationSettlementCount++
178 |                     DebugLogger.log("EXORCIST_GPS", "Settling GPS ($locationSettlementCount/3)...")
179 |                     return
180 |                 }
181 | 
182 |                 if (location.accuracy <= 12f) {
183 |                     LockManager.startLocation = location
184 |                     LockManager.currentDisplacement = 0f
185 |                     DebugLogger.log("EXORCIST_GPS", "Stable Anchor Set (Acc: ${location.accuracy}m)")
186 |                 } else {
187 |                     DebugLogger.log("EXORCIST_GPS", "Waiting for high accuracy lock... (Current: ${location.accuracy}m)")
188 |                 }
189 |             } else {
190 |                 // 1. Calculate delta from the PREVIOUS update, not the start
191 |                 val prev = lastLocation ?: start
192 |                 val deltaDist = prev.distanceTo(location)
193 |                 val totalFromStart = start.distanceTo(location)
194 |                 
195 |                 // 2. ANTI-SPOOF: Discard impossible jumps (> 15m in 1 sec = 54km/h)
196 |                 if (deltaDist > 15f || totalFromStart > 1000f) return
197 | 
198 |                 // 3. INTERLOCK: Only accumulate distance if the user stepped
199 |                 val currentSteps = LockManager.getWhisperSteps(applicationContext)
200 |                 if (currentSteps > lastVerifiedStepForDist) {
201 |                     // User moved their legs! We can trust this delta.
202 |                     LockManager.currentDisplacement += deltaDist
203 |                     lastVerifiedStepForDist = currentSteps
204 |                     DebugLogger.log("EXORCIST_GPS", "Accumulated +${deltaDist.toInt()}m. Total: ${LockManager.currentDisplacement.toInt()}m")
205 |                 } else {
206 |                     // Distance changed but steps didn't. This is jitter.
207 |                     DebugLogger.log("EXORCIST_SYNC", "Ignoring GPS Jitter (${deltaDist.toInt()}m) - No steps detected.")
208 |                 }
209 |                 lastLocation = location
210 |             }
211 |         }
212 |     }
